import React, { useEffect, useState } from 'react';
import { fetchCampaignOverview } from '../services/api';

export default function CampaignOverview() {
  const [data, setData] = useState(null);

  useEffect(() => {
    fetchCampaignOverview()
      .then((res) => setData(res.data))
      .catch(console.error);
  }, []);

  if (!data) return null;

  return (
    <div className="stats-row">
      <div className="stat-card">
        <div className="label">Total Videos</div>
        <div className="value">{data.totalVideos}</div>
      </div>
      <div className="stat-card">
        <div className="label">Total Views</div>
        <div className="value">{Number(data.totalViews).toLocaleString()}</div>
      </div>
      <div className="stat-card">
        <div className="label">Total Likes</div>
        <div className="value">{Number(data.totalLikes).toLocaleString()}</div>
      </div>
      <div className="stat-card">
        <div className="label">Total Shares</div>
        <div className="value">{Number(data.totalShares).toLocaleString()}</div>
      </div>
      <div className="stat-card">
        <div className="label">Total Saves</div>
        <div className="value">{Number(data.totalSaves).toLocaleString()}</div>
      </div>
      <div className="stat-card">
        <div className="label">Avg Engagement Rate</div>
        <div className="value accent">{data.avgEngagementRate}%</div>
      </div>
    </div>
  );
}
